（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:41+00:00", "source_pdf_sha1": "8f7413efa74f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "425", "s": "1108", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法物權編概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "地政"}'::jsonb, NULL),
  ('pukao-f29af906-moex-00046', 'pukao-f29af906', 'pukao-f29af906-moex-111-d3e6a6cd', 'sub-pukao-f29af906-02', NULL, 'essay', '甲在自有之 A 地上未依建築法規規定興建完成 B 屋（即無法為建物保
