律主張？（15 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:41+00:00", "source_pdf_sha1": "8f7413efa74f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "425", "s": "1108", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法物權編概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "地政"}'::jsonb, NULL)
